# RL-Cache: Per-content hit probability plot
# Data source: results_rl_cache.npz (generated by main.py --mode test or --mode both)
#
# Usage:
#   cd experiments/experiment0/plots
#   python plot_results.py

# Author: labry

import os
import numpy as np
import sys

SCRIPT_DIR = os.path.dirname(os.path.abspath(__file__))
REPO_ROOT = os.path.abspath(os.path.join(SCRIPT_DIR, '..', '..', '..'))
EXPERIMENT_DIR = os.path.abspath(os.path.join(SCRIPT_DIR, '..'))
sys.path.insert(0, '/home/labry/git/IcarusGym')
sys.path.insert(0, REPO_ROOT)

from matplotlib import pyplot


def plot_results_rl_cache():
    """Plot per-content cache hit probabilities from RL-Cache evaluation.

    Reads results_rl_cache.npz and plots:
        - X-axis: Content ID (1 to N, log scale)
        - Y-axis: Cache hit probability (log scale)
        - Title shows mean cache hit ratio
    """
    input_file = os.path.join(REPO_ROOT, 'results_rl_cache.npz')
    output_file = os.path.join(REPO_ROOT, 'results_rl_cache.png')

    if not os.path.exists(input_file):
        print(f'Error: {input_file} not found.')
        print(f'Run "python main.py --mode test" or "--mode both" first to generate results.')
        sys.exit(1)

    data = np.load(input_file)
    print(f'Loaded: {input_file}')
    print(f'  Keys: {list(data.keys())}')

    is_ = np.array(data['is_'], dtype=np.int32)
    hit_probs = np.array(data['hit_probs'], dtype=np.float64)
    request_counts = np.array(data['request_counts'], dtype=np.int32)
    hit_counts = np.array(data['hit_counts'], dtype=np.int32)
    mean_hit_ratio = float(data['mean_cache_hit_ratio'])

    n = len(hit_probs)
    xs = range(1, n + 1)

    print(f'  Contents: {n}')
    print(f'  Mean cache hit ratio: {mean_hit_ratio:.4f}')
    print(f'  Total requests: {request_counts.sum()}')
    print(f'  Total hits: {hit_counts.sum()}')

    # Clamp for log-scale plotting (avoid log(0))
    hit_probs_plot = np.maximum(hit_probs, 1e-10)

    pyplot.figure(figsize=(10, 6))
    line, = pyplot.plot(xs, hit_probs_plot, color='blue', marker='.', markersize=3, linewidth=1)
    pyplot.legend([line], [f'RL-Cache (mean hit ratio = {mean_hit_ratio:.4f})'])

    pyplot.xlabel('Content ID')
    pyplot.ylabel('Cache Hit Probability')
    pyplot.title(f'RL-Cache: Per-Content Cache Hit Probability')
    pyplot.xscale('log')
    pyplot.yscale('log')
    pyplot.ylim(1.25e-3, 1.20)
    pyplot.grid(True, which='both', alpha=0.3)
    pyplot.tight_layout()

    pyplot.savefig(output_file, dpi=150)
    print(f'Plot saved to {output_file}')


if __name__ == '__main__':
    plot_results_rl_cache()
